/*
  CA Permit Practice — Question Bank
  Content adapted from the California Driver Handbook (dmv.ca.gov) and
  official DMV Fast Facts publications. Categories mirror how the real
  46-question knowledge test is distributed across topics.
*/

const QUESTION_BANK = [

  // ===================== SIGNS =====================
  { id: "sg01", category: "signs", q: "A sign shaped like an octagon (eight sides) always means:", choices: ["Yield", "Stop", "Railroad crossing ahead", "No passing"], a: 1, exp: "The octagon shape is reserved exclusively for STOP signs anywhere in North America, so drivers can recognize it even if the sign is dirty or the word is missing." },
  { id: "sg02", category: "signs", q: "A downward-pointing triangle (point down) at an intersection means:", choices: ["Stop", "Yield the right-of-way", "No U-turn", "Merge"], a: 1, exp: "The triangle pointing down is a YIELD sign — slow down and let traffic and pedestrians clear before proceeding." },
  { id: "sg03", category: "signs", q: "Diamond-shaped signs are used to warn drivers about:", choices: ["Regulatory speed limits", "General warnings and hazards ahead", "Services like gas and food", "Historic or recreational sites"], a: 1, exp: "Diamond-shaped signs are warning signs — curves, merges, crossings, and other hazards ahead." },
  { id: "sg04", category: "signs", q: "A round (circular) sign specifically warns of:", choices: ["A school zone", "A railroad crossing ahead", "A hospital", "A construction zone"], a: 1, exp: "The circular shape is used only for advance railroad crossing warning signs." },
  { id: "sg05", category: "signs", q: "A pentagon-shaped sign (like home plate, point up) indicates:", choices: ["A school zone or school crossing", "A hospital zone", "A no-parking zone", "A one-way street"], a: 0, exp: "Pentagon-shaped signs mark schools and school crossings." },
  { id: "sg06", category: "signs", q: "Signs that are rectangular with the long side vertical usually give:", choices: ["Warnings about curves", "Regulatory information such as speed limits or one-way", "Directions to services", "Distances to the next town"], a: 1, exp: "Vertical rectangles are the standard shape for regulatory signs (speed limit, one-way, no turns)." },
  { id: "sg07", category: "signs", q: "What does a red sign or red road marking generally mean?", choices: ["Guide information", "Stop, do not enter, or wrong way", "Service ahead", "Construction area"], a: 1, exp: "Red is used only for STOP, DO NOT ENTER, WRONG WAY, and YIELD — signs you must obey." },
  { id: "sg08", category: "signs", q: "A yellow sign or yellow pavement marking is used mainly for:", choices: ["General warning of a hazard or condition", "Construction and maintenance zones", "Guiding you to a freeway exit", "Marking a recreational area"], a: 0, exp: "Yellow is the standard warning color for hazards, cross traffic, curves, and pedestrian areas." },
  { id: "sg09", category: "signs", q: "Orange signs and markings are used for:", choices: ["Guide information", "Construction, maintenance, and slow-moving vehicle warnings", "Motorist services", "School zones"], a: 1, exp: "Orange signals construction/maintenance areas — slow down and watch for workers." },
  { id: "sg10", category: "signs", q: "A green sign is most often used to show:", choices: ["Guide information such as directions, distances, and exits", "A speed limit change", "A stop is required ahead", "A railroad crossing"], a: 0, exp: "Green signs give directional/guide information — think freeway exit signs." },
  { id: "sg11", category: "signs", q: "Blue signs along the highway typically indicate:", choices: ["Motorist services such as gas, food, or lodging", "Recreational areas", "Warnings of hazards", "Regulatory speed limits"], a: 0, exp: "Blue is reserved for services useful to motorists — hospitals, gas, food, lodging." },
  { id: "sg12", category: "signs", q: "A brown sign along the road usually points you toward:", choices: ["A parks or recreational area", "A hospital", "A school", "A weigh station"], a: 0, exp: "Brown signs mark parks, recreation areas, and public campgrounds." },
  { id: "sg13", category: "signs", q: "You see a black-and-white rectangular sign posted on the highway. This is:", choices: ["A warning sign", "A regulatory sign giving laws you must obey", "A service sign", "A guide sign"], a: 1, exp: "White (with black text) signs give regulatory rules such as speed limits and turn restrictions." },
  { id: "sg14", category: "signs", q: "A crossbuck sign (shaped like an X) with 'RAILROAD CROSSING' written on it means:", choices: ["Yield to trains and be prepared to stop", "Proceed without slowing", "One way street ahead", "No trucks allowed"], a: 0, exp: "The crossbuck is a legal STOP/YIELD instruction — treat it like a yield sign unless a train is approaching, then you must stop." },
  { id: "sg15", category: "signs", q: "An orange, diamond-shaped sign showing a worker with a shovel means:", choices: ["Road work / construction zone ahead", "A recreation area", "A hospital ahead", "A rest stop"], a: 0, exp: "Orange diamond signs warn of construction or maintenance work; slow down and watch for workers." },
  { id: "sg16", category: "signs", q: "A sign showing a curved arrow with a speed shown below it (like a yellow curve sign with '35') means:", choices: ["The mandatory speed for the curve", "The recommended safe speed to take the curve", "The minimum legal speed on this road", "The speed limit that applies for the next 5 miles"], a: 1, exp: "That is an advisory speed — a recommended safe speed for the condition (like a curve), not a legal minimum or maximum by itself." },
  { id: "sg17", category: "signs", q: "A red-and-white triangular sign posted at an intersection is a:", choices: ["Stop sign", "Yield sign", "Do Not Enter sign", "Merge sign"], a: 1, exp: "Yield signs are red-and-white downward-pointing triangles." },
  { id: "sg18", category: "signs", q: "A red circle with a red diagonal slash over a symbol (like an arrow or a 'U') means:", choices: ["That action is required", "That action is prohibited", "Caution advised", "The sign is informational only"], a: 1, exp: "A circle-and-slash always means the pictured action is prohibited (e.g., no U-turn, no left turn)." },
  { id: "sg19", category: "signs", q: "A white rectangular sign reading 'ONE WAY' with an arrow tells you:", choices: ["Traffic on that street moves only in the direction of the arrow", "You may travel in either direction", "The street is closed", "You must yield before entering"], a: 0, exp: "One-way signs mean ALL traffic on that street travels only in the arrow's direction." },
  { id: "sg20", category: "signs", q: "What shape is used specifically to alert you that you are approaching a school zone or crosswalk?", choices: ["Octagon", "Pentagon (five-sided, point up)", "Diamond", "Circle"], a: 1, exp: "The five-sided 'home plate' shape is used only for school-related signs." },
  { id: "sg21", category: "signs", q: "A sign with a black arrow bent sharply back on a yellow diamond warns of:", choices: ["A sharp turn or hairpin curve ahead", "A dead end", "A merging lane", "A divided highway"], a: 0, exp: "A sharply bent arrow warns of a sharp curve or hairpin turn — slow down before you reach it." },
  { id: "sg22", category: "signs", q: "A 'DO NOT ENTER' sign is:", choices: ["A red and white square/rectangle sign", "A yellow diamond sign", "A green rectangular sign", "A blue circular sign"], a: 0, exp: "DO NOT ENTER signs are white symbols on a red square background, posted where entry is prohibited (like a freeway off-ramp)." },
  { id: "sg23", category: "signs", q: "You see a yellow pennant (flag-shaped) sign on the left side of the road. This means:", choices: ["No passing zone begins", "A hospital is ahead", "A speed limit change", "A rest area ahead"], a: 0, exp: "The pennant-shaped sign marks the beginning of a no-passing zone." },
  { id: "sg24", category: "signs", q: "A sign showing two arrows pointing in opposite directions on a divided road means:", choices: ["Divided highway begins", "Divided highway ends", "Two-way traffic ahead", "Do not enter"], a: 2, exp: "This warns that the road changes from a divided highway to a normal two-way road ahead." },
  { id: "sg25", category: "signs", q: "A flashing yellow traffic light at an intersection means you should:", choices: ["Stop completely, then proceed when safe", "Slow down and proceed with caution", "Speed up to clear the intersection", "Treat it the same as a flashing red light"], a: 1, exp: "Flashing yellow means caution — slow down, look both ways, and proceed carefully; it does not require a full stop." },

  // ===================== SIGNALS & MARKINGS =====================
  { id: "sm01", category: "signals", q: "A steady red traffic signal light means you must:", choices: ["Stop and stay stopped until the light turns green", "Slow down but you may proceed if clear", "Stop, then proceed if no cross traffic (like a stop sign)", "Yield only to pedestrians"], a: 0, exp: "A steady red light requires a complete stop and you must remain stopped until it turns green (right turns on red are a separate rule where permitted)." },
  { id: "sm02", category: "signals", q: "A flashing red traffic signal means the same thing as a:", choices: ["Yield sign", "Stop sign — stop, then proceed when safe", "Do not enter sign", "Railroad crossing signal"], a: 1, exp: "A flashing red signal is treated exactly like a stop sign." },
  { id: "sm03", category: "signals", q: "A single solid yellow line on your side of the centerline means:", choices: ["Passing is allowed when safe", "You may not pass", "The lane is for turning only", "The lane ends ahead"], a: 1, exp: "A solid yellow line on your side prohibits passing; a broken yellow line on your side allows passing when safe." },
  { id: "sm04", category: "signals", q: "Two solid yellow lines together in the center of the road mean:", choices: ["Passing is allowed in both directions", "You must never cross them except to turn left into a driveway or make a U-turn where legal", "They mark a bike lane", "They indicate a one-way street"], a: 1, exp: "Double solid yellow lines are a strict no-passing barrier except when turning left." },
  { id: "sm05", category: "signals", q: "A white line with a row of solid triangles pointing toward you across a lane is called a:", choices: ["Limit line", "Yield line", "Gore line", "Edge line"], a: 1, exp: "A yield line (row of triangles) shows drivers exactly where to yield or stop for cross traffic." },
  { id: "sm06", category: "signals", q: "Double solid white lines on the freeway mean:", choices: ["You may change lanes freely", "Lane changes are strongly discouraged/prohibited across them", "The lane ends", "Carpool lane access is open to everyone"], a: 1, exp: "Never change lanes across double solid white lines — commonly used at carpool (HOV) lane boundaries." },
  { id: "sm07", category: "signals", q: "A wide white line painted across your lane at an intersection is a:", choices: ["Yield line", "Limit line, showing where to stop", "Crosswalk boundary only", "Bike lane marker"], a: 1, exp: "The limit line marks exactly where you must stop for a stop sign or red light — before the crosswalk." },
  { id: "sm08", category: "signals", q: "A flashing yellow arrow at a signal, when making a left turn, means:", choices: ["Left turns are prohibited", "You may turn left after yielding to oncoming traffic and pedestrians", "Stop, no turns allowed", "Proceed straight only"], a: 1, exp: "A flashing yellow arrow allows a left turn, but you must yield to oncoming traffic and pedestrians first." },
  { id: "sm09", category: "signals", q: "A green arrow signal pointing left means:", choices: ["You have the right-of-way to turn left; oncoming traffic has a red light", "You must yield to all oncoming traffic before turning", "Left turns are prohibited", "Proceed straight only"], a: 0, exp: "A green arrow gives a protected turn — oncoming traffic is stopped, so you have the right-of-way." },
  { id: "sm10", category: "signals", q: "If a traffic signal is not working at all (dark/no power), you should treat the intersection as:", choices: ["A yield-only intersection", "A four-way stop", "A no-right-turn intersection", "Free to pass through without stopping"], a: 1, exp: "A dead traffic signal must be treated as an all-way stop — take turns in the order you arrived." },

  // ===================== RIGHT OF WAY =====================
  { id: "rw01", category: "row", q: "At a four-way stop where two vehicles arrive at the same time, the right-of-way goes to:", choices: ["The vehicle on the left", "The vehicle on the right", "Whichever vehicle is bigger", "Whoever honks first"], a: 1, exp: "When two vehicles reach a stop at the same time, the driver on the left must yield to the driver on the right." },
  { id: "rw02", category: "row", q: "At an intersection with no signs or signals at all (an uncontrolled intersection), you should:", choices: ["Proceed at full speed since no one has the right of way", "Slow down and yield to any vehicle already in the intersection or arriving first", "Always stop completely no matter what", "Only yield to vehicles turning left"], a: 1, exp: "At uncontrolled intersections, slow down and yield to traffic already there or arriving at roughly the same time from the right." },
  { id: "rw03", category: "row", q: "When entering a roundabout, you must yield to:", choices: ["Traffic already circulating in the roundabout", "Traffic waiting to enter behind you", "No one — entering traffic always has the right of way", "Only pedestrians"], a: 0, exp: "Vehicles already inside the roundabout have the right-of-way; wait for a safe gap before entering, and travel counterclockwise." },
  { id: "rw04", category: "row", q: "When two vehicles reach an uncontrolled intersection at the same time from directions at a right angle to each other, who yields?", choices: ["The driver on the right has the right of way", "The driver on the left has the right of way", "Whoever is going straight always wins", "It is always a tie and both must reverse"], a: 0, exp: "The basic right-of-way rule: yield to the vehicle approaching from your right." },
  { id: "rw05", category: "row", q: "You are turning left at an intersection with a green light and no arrow. Oncoming traffic is clear. You should:", choices: ["Wait for a green arrow no matter what", "Yield to oncoming traffic and pedestrians, then complete the turn when safe", "Proceed immediately since you have a green light", "Turn only if a police officer directs you"], a: 1, exp: "A green light without an arrow means you may turn left, but only after yielding to oncoming vehicles and pedestrians." },
  { id: "rw06", category: "row", q: "When approaching a narrow, one-lane mountain road with no signs and another car coming uphill, who has the right of way?", choices: ["The vehicle going downhill has the right of way", "The vehicle going uphill has the right of way", "Whichever car is closer to a turnout", "Whoever arrives at the narrow section first"], a: 1, exp: "On mountain grades, the vehicle traveling uphill has the right-of-way because it is harder to restart on a slope; the downhill driver should yield/back up to a turnout if needed." },
  { id: "rw07", category: "row", q: "A pedestrian is crossing at a marked or unmarked crosswalk with no traffic signal. You must:", choices: ["Stop and yield the right-of-way to the pedestrian", "Only stop if the pedestrian is more than halfway across", "Proceed if you can pass behind them", "Honk to make them hurry"], a: 0, exp: "Drivers must always yield to pedestrians in a crosswalk, marked or unmarked." },
  { id: "rw08", category: "row", q: "You approach a stopped school bus with red lights flashing on a two-lane undivided road. You must:", choices: ["Stop in both directions until lights stop flashing and children clear", "Only stop if traveling behind the bus", "Slow to 10 mph and proceed carefully", "Pass if no children are visible"], a: 0, exp: "Traffic in both directions must stop for a school bus with flashing red lights on an undivided road." },
  { id: "rw09", category: "row", q: "You are merging onto the freeway from an on-ramp. Who generally has the right of way?", choices: ["Merging traffic always has priority", "Traffic already on the freeway generally has priority; merge when there is a safe gap", "Whoever is driving faster", "The merging lane always ends so you must stop"], a: 1, exp: "Freeway traffic already flowing has priority — adjust your speed and merge into a gap safely, don't force your way in." },
  { id: "rw10", category: "row", q: "An ambulance or fire engine approaches from behind with lights and siren on. You should:", choices: ["Speed up to clear the intersection first", "Pull to the right edge of the road and stop until it passes", "Stop immediately in your current lane", "Ignore it if you are already going the speed limit"], a: 1, exp: "Yield the right-of-way to emergency vehicles by pulling to the right and stopping until they pass, unless directed otherwise." },
  { id: "rw11", category: "row", q: "You come to a blind intersection where you can't see cross traffic and there are no stop signs. California law says you should:", choices: ["Not exceed 15 mph and be prepared to stop", "Proceed at the normal speed limit", "Always come to a complete stop", "Honk continuously through the intersection"], a: 0, exp: "At a blind intersection, the speed limit is 15 mph unless posted otherwise, so you have time to react." },
  { id: "rw12", category: "row", q: "When you see a 'YIELD' sign, you must:", choices: ["Always come to a complete stop", "Slow down, and stop if necessary, to let traffic and pedestrians clear before proceeding", "Maintain your speed since you have the right of way", "Only slow down for pedestrians, not vehicles"], a: 1, exp: "A yield sign means slow down and be ready to stop if there isn't a safe gap in traffic or pedestrians present." },
  { id: "rw13", category: "row", q: "Two vehicles enter an intersection from opposite directions at the same time — one going straight, one turning left. Who yields?", choices: ["The vehicle turning left must yield to the oncoming vehicle going straight", "The vehicle going straight must yield", "Whoever arrived first", "The larger vehicle has the right of way"], a: 0, exp: "A left-turning vehicle must always yield to oncoming traffic going straight or turning right." },
  { id: "rw14", category: "row", q: "When you're driving and a vehicle is entering the roadway from a private driveway or alley, who has the right of way?", choices: ["The vehicle already on the roadway", "The vehicle entering from the driveway/alley", "Whichever vehicle is moving faster", "Neither, both must stop and wait for a police officer"], a: 0, exp: "Vehicles entering a roadway from a private road, driveway, or alley must yield to traffic already on the road." },
  { id: "rw15", category: "row", q: "In a roundabout, which direction do you travel?", choices: ["Clockwise", "Counterclockwise", "Either direction is fine", "Only straight through, never circulating"], a: 1, exp: "In the U.S., traffic in a roundabout always moves counterclockwise, yielding to traffic already inside." },

  // ===================== SPEED LIMITS / BASIC SPEED LAW =====================
  { id: "sp01", category: "speed", q: "California's 'Basic Speed Law' means you should never drive:", choices: ["Faster than the posted limit under any circumstance", "Faster than is safe for current conditions, even if that's below the posted limit", "Slower than other traffic no matter what", "Below 25 mph on any street"], a: 1, exp: "The Basic Speed Law requires driving at a speed that's safe for conditions (traffic, weather, visibility) — sometimes that's well under the posted limit." },
  { id: "sp02", category: "speed", q: "Unless otherwise posted, the speed limit in a residential or business district in California is:", choices: ["15 mph", "25 mph", "35 mph", "45 mph"], a: 1, exp: "The default prima facie speed limit for residential and business districts is 25 mph unless signs say otherwise." },
  { id: "sp03", category: "speed", q: "Unless otherwise posted, the speed limit when passing a school while children are present (school zone) is:", choices: ["15 mph", "25 mph", "35 mph", "45 mph"], a: 1, exp: "School zone speed limit is 25 mph when children are present, unless a lower limit is posted." },
  { id: "sp04", category: "speed", q: "The speed limit at a blind railroad crossing (can't see track for 400 feet) is:", choices: ["15 mph", "25 mph", "35 mph", "5 mph"], a: 0, exp: "You must not exceed 15 mph when approaching a railroad crossing where visibility is blocked." },
  { id: "sp05", category: "speed", q: "The speed limit at a blind intersection (no stop signs, obstructed view) is:", choices: ["15 mph", "25 mph", "35 mph", "45 mph"], a: 0, exp: "Blind intersections carry a 15 mph limit unless otherwise posted, since you can't see cross traffic." },
  { id: "sp06", category: "speed", q: "The maximum speed limit on most California highways/freeways, unless posted otherwise, is:", choices: ["55 mph", "65 mph", "70 mph", "75 mph"], a: 2, exp: "65 mph is common, but many California freeways are posted at 70 mph — always follow the posted sign, which can vary by segment." },
  { id: "sp07", category: "speed", q: "In heavy rain or snow with visibility of less than 100 feet, you should not drive faster than:", choices: ["55 mph", "40 mph", "30 mph", "20 mph"], a: 2, exp: "The handbook advises not exceeding 30 mph when visibility drops below 100 feet due to heavy rain, snow, or fog." },
  { id: "sp08", category: "speed", q: "You are driving in the fast lane and a driver behind you wants to pass. You should:", choices: ["Speed up so they can't pass", "Move to a lane on your right when safe to let them by", "Brake suddenly to discourage tailgating", "Flash your brake lights repeatedly"], a: 1, exp: "Move over when it's safe to let faster traffic pass rather than blocking or speeding up." },
  { id: "sp09", category: "speed", q: "On packed snow, the safe driving speed should be reduced by about:", choices: ["10%", "25%", "50%", "No reduction needed if you have 4WD"], a: 2, exp: "The handbook recommends cutting your speed by about half (50%) on packed snow." },
  { id: "sp10", category: "speed", q: "On wet roads, you should generally reduce your speed by about:", choices: ["0-2 mph", "5-10 mph", "20-25 mph", "30-40 mph"], a: 1, exp: "A 5-10 mph reduction is recommended on wet pavement to maintain traction and control." },
  { id: "sp11", category: "speed", q: "On icy roads, you should slow to a maximum of about:", choices: ["5 mph", "15 mph", "25 mph", "35 mph"], a: 0, exp: "Ice provides very little traction — the handbook advises no more than about 5 mph, or avoid driving if possible." },
  { id: "sp12", category: "speed", q: "Driving too slowly on a highway compared to the flow of traffic can:", choices: ["Never be a problem or a violation", "Be just as dangerous and against the Basic Speed Law as driving too fast", "Only matter in the far left lane", "Only matter at night"], a: 1, exp: "Driving unreasonably slowly can impede traffic flow and create hazards, which also violates the Basic Speed Law." },

  // ===================== TURNING, PASSING, LANES =====================
  { id: "tp01", category: "turning", q: "Before turning, you should signal continuously for at least:", choices: ["100 feet before the turn", "500 feet before the turn", "10 feet before the turn", "You don't need to signal if no cars are around"], a: 0, exp: "Signal about 100 feet before turning so drivers behind and beside you have time to react." },
  { id: "tp02", category: "turning", q: "When making a right turn, you should position your vehicle:", choices: ["In the center of the road", "As close as practical to the right-hand curb or edge", "In the left lane", "Anywhere, as long as you signal"], a: 1, exp: "Stay close to the right edge of the roadway when turning right to avoid cutting off other lanes." },
  { id: "tp03", category: "turning", q: "Passing is prohibited when within how many feet of an intersection, bridge, tunnel, or railroad crossing?", choices: ["50 feet", "100 feet", "200 feet", "500 feet"], a: 1, exp: "You may not pass within 100 feet of intersections, bridges, tunnels, or railroad crossings." },
  { id: "tp04", category: "turning", q: "You want to pass a slower vehicle on a two-lane road. It is legal to pass on the right when:", choices: ["Never, passing on the right is always illegal", "The vehicle ahead is signaling a left turn and there is room to pass safely on the right", "You are in a hurry", "There is a solid yellow line"], a: 1, exp: "Passing on the right is allowed only in specific situations, such as when a vehicle ahead is turning left and there's a safe paved area to pass, or on a multi-lane road/one-way street." },
  { id: "tp05", category: "turning", q: "A center two-way left-turn lane (marked with yellow lines on both sides) may be used to:", choices: ["Pass slower traffic", "Merge into for making a left turn, for no more than about 200 feet before turning", "Drive in for extended distances", "Park temporarily"], a: 1, exp: "The center turn lane is only for entering/exiting a left turn — don't drive in it for long distances." },
  { id: "tp06", category: "turning", q: "Before changing lanes, you should always:", choices: ["Just use your mirrors", "Signal, check mirrors, and check your blind spot over your shoulder", "Speed up first", "Only check the rearview mirror"], a: 1, exp: "A full check — mirrors, signal, and a head/shoulder check for blind spots — is required before every lane change." },
  { id: "tp07", category: "turning", q: "U-turns are illegal in which of these situations?", choices: ["On a residential street with clear visibility", "In front of a fire station", "At an intersection with a green light (where not posted otherwise)", "On a divided highway with an opening in the median"], a: 1, exp: "U-turns are prohibited in front of fire stations, on highways where prohibited by sign, in business districts (except at intersections), and at railroad crossings." },
  { id: "tp08", category: "turning", q: "A double solid yellow line in the center of the road can only be legally crossed to:", choices: ["Pass a slower vehicle when the road ahead is clear", "Turn left into or out of a driveway, or make a legal U-turn", "Enter a bike lane", "Avoid a pothole"], a: 1, exp: "Double solid yellow lines may only be crossed for a left turn or legal U-turn — not for passing." },
  { id: "tp09", category: "turning", q: "When you want to turn right on red after stopping, you must first:", choices: ["Check for a 'No Turn on Red' sign and yield to pedestrians/cross traffic", "Wait for the light to turn green", "Only check your mirrors", "Honk before proceeding"], a: 0, exp: "Right turns on red are allowed after a complete stop, unless a sign prohibits it, and only after yielding to pedestrians and cross traffic." },
  { id: "tp10", category: "turning", q: "A broken white line between two lanes moving in the same direction means:", choices: ["You may change lanes when safe", "Lane changes are prohibited", "This is a passing zone against oncoming traffic", "You must merge immediately"], a: 0, exp: "A broken white line separates same-direction lanes and permits lane changes when safe to do so." },
  { id: "tp11", category: "turning", q: "You may cross a single broken yellow centerline to pass when:", choices: ["It is on your side and the way ahead is clear of oncoming traffic", "It is on the other driver's side only", "There is a solid yellow line right next to it on your side", "Never, broken yellow lines still prohibit passing"], a: 0, exp: "A broken yellow line on your side of centerline permits passing if it's safe and clear of oncoming traffic." },
  { id: "tp12", category: "turning", q: "When two vehicles are turning left toward each other from opposite directions at the same intersection, they should:", choices: ["Pass in front of one another", "Turn to the left of each other (each passing behind the other's path)", "Wait for a police officer", "Whoever is bigger goes first"], a: 1, exp: "Opposing left turns should pass to the left of each other, keeping to the right of the intersection's center." },

  // ===================== PARKING =====================
  { id: "pk01", category: "parking", q: "A red curb means:", choices: ["Loading zone for freight only", "No stopping, standing, or parking at any time", "15-minute parking allowed", "Disabled parking only"], a: 1, exp: "Red curbs prohibit stopping, standing, or parking, no exceptions." },
  { id: "pk02", category: "parking", q: "A blue curb is reserved for:", choices: ["Passenger loading only", "Vehicles displaying a valid disabled person placard or plate", "Short-term parking under 10 minutes", "Delivery trucks only"], a: 1, exp: "Blue curbs are reserved for vehicles with valid disabled parking placards or plates." },
  { id: "pk03", category: "parking", q: "A white curb generally means:", choices: ["Parking for government vehicles only", "Stopping only long enough to load/unload passengers or mail", "No parking during street cleaning", "Reserved for motorcycles"], a: 1, exp: "White curbs are for brief passenger loading/unloading (or mail drop) only." },
  { id: "pk04", category: "parking", q: "A yellow curb is used for:", choices: ["Loading/unloading passengers and freight within the posted time limit", "Disabled parking", "Free unlimited parking", "Fire lane only"], a: 0, exp: "Yellow curbs are for loading/unloading passengers or freight, generally limited to the posted time." },
  { id: "pk05", category: "parking", q: "When parking uphill on a street with a curb, you should turn your front wheels:", choices: ["Toward the curb", "Away from the curb", "Straight ahead", "It doesn't matter as long as the parking brake is set"], a: 1, exp: "Uphill with a curb: turn wheels away from the curb so the car rolls back a few inches and the tire rests against the curb if the brakes fail." },
  { id: "pk06", category: "parking", q: "When parking downhill, you should turn your front wheels:", choices: ["Away from the curb", "Toward the curb", "Straight ahead", "Turned all the way to the left regardless of curb side"], a: 1, exp: "Downhill: turn your wheels toward the curb so the vehicle rolls into the curb if it starts moving." },
  { id: "pk07", category: "parking", q: "You may not park within how many feet of a fire hydrant?", choices: ["5 feet", "10 feet", "15 feet", "25 feet"], a: 2, exp: "California law prohibits parking within 15 feet of a fire hydrant." },
  { id: "pk08", category: "parking", q: "You may not park within how many feet of a marked or unmarked crosswalk (unless a space is specifically marked)?", choices: ["5 feet", "10 feet", "20 feet", "30 feet"], a: 2, exp: "Parking is prohibited within 20 feet of a marked or unmarked crosswalk at an intersection." },
  { id: "pk09", category: "parking", q: "When parallel parking, once your rear wheel is about 18 inches from the curb while backing at an angle, you should:", choices: ["Continue backing at the same angle", "Begin turning the wheel to straighten out and pull in parallel to the curb", "Pull forward immediately and try again", "Stop and put the car in park"], a: 1, exp: "At about 18 inches from the curb, straighten your wheels and continue backing slowly to end up parallel and close to the curb." },
  { id: "pk10", category: "parking", q: "Legally, when parallel parking your final position should be within how many inches of the curb?", choices: ["6 inches", "18 inches", "36 inches", "It doesn't matter as long as you're not blocking traffic"], a: 1, exp: "California requires you to park within 18 inches of the curb." },

  // ===================== RAILROAD CROSSINGS =====================
  { id: "rr01", category: "railroad", q: "When a railroad crossing's flashing red lights are activated, you must:", choices: ["Speed up to beat the train", "Stop and not proceed until the lights stop flashing and it's safe", "Proceed slowly if you don't see a train", "Only stop if the gates are down"], a: 1, exp: "Flashing red lights mean a train is approaching — stop and wait until they stop flashing." },
  { id: "rr02", category: "railroad", q: "You must stop no closer than how many feet from the nearest rail when a railroad crossing signal is active?", choices: ["5 feet", "15 feet", "30 feet", "50 feet"], a: 1, exp: "Stop at least 15 feet from the nearest rail when warning devices are activated or a train is visible/audible." },
  { id: "rr03", category: "railroad", q: "If the crossing gates are down or lowering at a railroad crossing, you should:", choices: ["Drive around them if no train is visible", "Never go around or under a lowered gate", "Wait 10 seconds then proceed", "Only stop if you hear a whistle"], a: 1, exp: "Never drive around or under lowered crossing gates — it's illegal and extremely dangerous." },
  { id: "rr04", category: "railroad", q: "At a railroad crossing without any gates or flashing lights (a crossbuck sign only), you should:", choices: ["Proceed without slowing since there's no signal", "Treat it like an intersection and yield/stop as needed, watching for trains", "Only slow down if you hear a horn", "Always come to a complete stop no matter what"], a: 1, exp: "A crossbuck alone requires you to look both ways, slow down, and yield or stop if a train is approaching." },
  { id: "rr05", category: "railroad", q: "You should never shift gears while crossing railroad tracks because:", choices: ["It could stall your vehicle on the tracks", "It's illegal in California", "It damages the transmission permanently", "It has no real effect, this is a myth"], a: 0, exp: "Shifting gears on the tracks risks stalling your vehicle in the path of a train — shift beforehand." },
  { id: "rr06", category: "railroad", q: "Which vehicles are legally required to stop before crossing railroad tracks regardless of signals?", choices: ["Motorcycles only", "Vehicles carrying hazardous materials placards, and some buses", "Any vehicle with more than 2 passengers", "Electric vehicles"], a: 1, exp: "Vehicles hauling hazardous materials (and certain buses) must always stop before crossing train tracks." },

  // ===================== SCHOOL BUS =====================
  { id: "sb01", category: "schoolbus", q: "When a school bus ahead of you has red lights flashing and the stop arm extended, you must:", choices: ["Slow down and pass carefully", "Stop until the lights stop flashing and the arm is retracted", "Only stop if you see children", "Proceed if you're in the opposite lane"], a: 1, exp: "Traffic from both directions must stop for a school bus loading/unloading children with red lights flashing, except on a divided highway." },
  { id: "sb02", category: "schoolbus", q: "On a divided highway (with a physical median), do you need to stop for a school bus loading children on the OPPOSITE side?", choices: ["Yes, always", "No, only vehicles on the same side as the bus must stop", "Only during school hours", "Only if there's no shoulder"], a: 1, exp: "On divided highways with a physical barrier or unpaved median, only traffic traveling in the same direction as the bus must stop." },
  { id: "sb03", category: "schoolbus", q: "Failing to stop for a school bus with flashing red lights can result in a fine up to:", choices: ["$100", "$250", "$1,000 and a one-year license suspension", "There is no specific penalty"], a: 2, exp: "Penalties can include a fine of up to $1,000 and a one-year suspension of driving privileges." },
  { id: "sb04", category: "schoolbus", q: "A school bus with yellow lights flashing (not red) means:", choices: ["The bus is about to stop — prepare to stop", "You must stop immediately", "Children have finished crossing", "It's safe to pass at normal speed"], a: 0, exp: "Yellow flashing lights are a warning that the bus is slowing to stop; red flashing lights mean stop." },

  // ===================== ALCOHOL & DRUGS =====================
  { id: "ad01", category: "alcohol", q: "For drivers under 21 in California, the legal blood alcohol concentration (BAC) limit is:", choices: ["0.08%", "0.05%", "0.01%", "0.00% with no exceptions ever"], a: 2, exp: "California's Zero Tolerance Law sets the limit at 0.01% BAC for drivers under 21 — essentially any measurable alcohol is illegal." },
  { id: "ad02", category: "alcohol", q: "The legal BAC limit for drivers 21 and older in California is:", choices: ["0.05%", "0.08%", "0.10%", "0.12%"], a: 1, exp: "0.08% is the legal limit for drivers 21 and over operating a regular passenger vehicle." },
  { id: "ad03", category: "alcohol", q: "If a driver under 21 is caught with a BAC of 0.01% or higher, the DMV can suspend their license for:", choices: ["30 days", "6 months", "1 year", "There is no suspension for a first offense"], a: 2, exp: "A minor caught driving with any measurable alcohol (0.01%+) faces a one-year license suspension under the Zero Tolerance Law." },
  { id: "ad04", category: "alcohol", q: "California's 'implied consent' law means that by driving, you have already agreed to:", choices: ["Pay any traffic fine on the spot", "Submit to a chemical test (breath, blood, or urine) if lawfully arrested for DUI", "Allow police to search your entire vehicle at any time", "Take a field sobriety test only if you choose"], a: 1, exp: "Implied consent means drivers agree to chemical testing if arrested for DUI; refusing carries automatic penalties." },
  { id: "ad05", category: "alcohol", q: "Refusing a chemical test after being lawfully arrested for DUI in California results in:", choices: ["No consequence if you're found not guilty later", "An automatic license suspension/revocation, regardless of the DUI case outcome", "A warning only for a first offense", "Only a small fine"], a: 1, exp: "Refusal triggers an automatic license suspension or revocation independent of the criminal case." },
  { id: "ad06", category: "alcohol", q: "The BAC limit for drivers operating a commercial vehicle or driving for hire (like rideshare while carrying passengers) is:", choices: ["0.08%", "0.04%", "0.01%", "0.00%"], a: 1, exp: "Commercial and for-hire drivers face a stricter 0.04% BAC limit." },
  { id: "ad07", category: "alcohol", q: "Which of the following can impair your driving even though it's legal and doesn't require a prescription?", choices: ["Only illegal drugs impair driving", "Over-the-counter medications like cold or allergy medicine", "Bottled water", "Sunglasses"], a: 1, exp: "Many legal over-the-counter medications (antihistamines, cold medicine) cause drowsiness and impair driving ability." },
  { id: "ad08", category: "alcohol", q: "A DUI conviction stays on your driving record for how many years in California?", choices: ["1 year", "3 years", "10 years", "It's removed after paying the fine"], a: 2, exp: "DUI convictions remain on your record for 10 years and can increase penalties for any future offense in that window." },
  { id: "ad09", category: "alcohol", q: "Mixing alcohol with energy drinks or caffeine:", choices: ["Cancels out the effects of alcohol", "Can make you feel more alert than you actually are, while impairment remains", "Is completely safe", "Reduces your BAC"], a: 1, exp: "Caffeine can mask feelings of sleepiness without reducing actual impairment — you can still be legally and functionally impaired." },
  { id: "ad10", category: "alcohol", q: "As a provisional (under-18) license holder, if you are convicted of a DUI, in addition to license consequences you may face:", choices: ["No additional consequences beyond a normal ticket", "Mandatory DUI education programs and extended restriction periods", "Automatic loss of your Social Security number", "A permanent ban from ever applying again"], a: 1, exp: "Minors convicted of alcohol or drug-related driving offenses typically face DUI program requirements plus license consequences." },
  { id: "ad11", category: "alcohol", q: "It is illegal to have an open container of alcohol in a moving vehicle:", choices: ["Only if the driver is drinking it", "Anywhere in the passenger compartment, even for passengers, in most circumstances", "Only in the front seat", "Only if you're under 21"], a: 1, exp: "California's open container law generally prohibits open alcohol containers in the passenger area for both drivers and passengers." },
  { id: "ad12", category: "alcohol", q: "Which combination is most dangerous and most likely to result in a fatal crash?", choices: ["Driving tired but sober", "Drinking alcohol and then driving", "Driving with passengers", "Driving during the day"], a: 1, exp: "Alcohol is a leading factor in fatal crashes because it impairs judgment, reaction time, and coordination." },
  { id: "ad13", category: "alcohol", q: "Marijuana use, even where legal for adults, and driving:", choices: ["Is always legal to combine since marijuana is legal in California", "Is illegal if it impairs your ability to drive safely, and even trace use can trigger DUI charges for minors", "Only matters if you smoke while driving", "Has no effect on reaction time"], a: 1, exp: "Driving under the influence of marijuana is illegal; for drivers under 21, the Zero Tolerance Law effectively bans any drug or alcohol use before driving." },
  { id: "ad14", category: "alcohol", q: "How long does it typically take the body to eliminate the alcohol from one standard drink?", choices: ["A few minutes", "About one hour", "About 24 hours", "Alcohol is never eliminated"], a: 1, exp: "The body metabolizes roughly one standard drink per hour; coffee, cold showers, or food do not speed this up." },
  { id: "ad15", category: "alcohol", q: "For a driver under 21, refusing a preliminary alcohol screening (PAS) test when lawfully requested results in:", choices: ["No consequence since they are a minor", "License suspension under the Zero Tolerance implied consent rules", "A warning only", "A requirement to retake the written test"], a: 1, exp: "Underage drivers are still subject to implied consent — refusal leads to license suspension." },

  // ===================== SEATBELTS & SAFETY =====================
  { id: "sb-1", category: "safety", q: "In California, seat belts are required for:", choices: ["Only the driver", "The driver and front-seat passenger only", "The driver and all passengers in every seating position", "Only passengers under 18"], a: 2, exp: "California law requires the driver and all passengers, front and back, to wear seat belts." },
  { id: "sb-2", category: "safety", q: "Children under age 2 must ride in:", choices: ["A rear-facing car seat unless they exceed the height/weight limit for it", "A regular seat belt", "The front seat if supervised", "A forward-facing booster seat"], a: 0, exp: "California requires rear-facing car seats for children under 2 unless they exceed the manufacturer's height/weight limits." },
  { id: "sb-3", category: "safety", q: "Generally, children must ride in a car seat or booster until they are:", choices: ["8 years old OR 4 feet 9 inches tall, whichever comes first", "5 years old regardless of height", "12 years old always", "There is no such requirement in California"], a: 0, exp: "California requires a car seat/booster until age 8 or 4'9\" tall, whichever happens first." },
  { id: "sb-4", category: "safety", q: "Airbags work best and are safest when used:", choices: ["Instead of seat belts", "Together with a properly worn seat belt", "Only in the front seat with no belt", "Only for adults over 200 lbs"], a: 1, exp: "Airbags supplement seat belts; they are not a substitute and can cause injury if the seat belt isn't worn correctly." },
  { id: "sb-5", category: "safety", q: "Children 12 and under should generally ride:", choices: ["In the front passenger seat for a better view", "In the back seat, properly restrained", "Wherever there is room", "Standing between seats if belted"], a: 1, exp: "The back seat is safer for children 12 and under, primarily due to airbag deployment risks in front." },
  { id: "sb-6", category: "safety", q: "Using a handheld cell phone to talk while driving in California is:", choices: ["Legal for all drivers", "Illegal for all drivers except in a genuine emergency; hands-free is allowed for adults", "Only illegal for drivers under 21", "Legal as long as you're stopped at a red light"], a: 1, exp: "California bans holding a phone while driving; hands-free use is allowed for licensed adults 18+, but any cell phone use (even hands-free) is prohibited for provisional (under-18) drivers." },
  { id: "sb-7", category: "safety", q: "As a provisional license holder under 18, using a cell phone — even hands-free — while driving is:", choices: ["Completely legal", "Prohibited, except in an emergency to call police, fire, or medical help", "Only prohibited after 11 p.m.", "Allowed only for GPS use"], a: 1, exp: "Drivers under 18 may not use any wireless device while driving, hands-free or not, except to contact emergency services." },
  { id: "sb-8", category: "safety", q: "You are stopped by a broken-down vehicle on the freeway shoulder with its hazard lights on. You should:", choices: ["Ignore it and maintain your lane and speed", "Move over a lane if possible, or slow down, to give it space", "Speed up to pass quickly", "Stop directly behind it to help"], a: 1, exp: "California's 'Move Over' expectation applies broadly — give stopped vehicles (and especially emergency/utility vehicles) extra space by changing lanes or slowing when safe." },

  // ===================== SHARING THE ROAD =====================
  { id: "sr01", category: "sharing", q: "When passing a bicyclist, California law requires you to leave at least:", choices: ["1 foot of space", "3 feet of space", "6 inches of space", "No specific distance is required"], a: 1, exp: "California's Three Feet for Safety law requires drivers to leave at least 3 feet when passing a bicyclist, or slow to a safe speed if 3 feet isn't possible." },
  { id: "sr02", category: "sharing", q: "A motorcycle is entitled to:", choices: ["Less than a full lane of space", "A full lane width, the same as any other vehicle", "Only the right portion of a lane", "Half the space of a car"], a: 1, exp: "Motorcycles have full use of a traffic lane — never share a lane with a motorcycle side-by-side." },
  { id: "sr03", category: "sharing", q: "When following a motorcyclist, you should allow extra following distance because:", choices: ["Motorcycles can stop much more slowly than cars", "Motorcycles can stop suddenly and are harder to see", "Motorcycles are required to always drive faster", "There's no need for extra distance"], a: 1, exp: "Motorcycles can decelerate quickly and are smaller/harder to spot, so extra following distance is safer." },
  { id: "sr04", category: "sharing", q: "Large trucks have bigger blind spots than cars, especially:", choices: ["Directly in front of the cab only", "Along both sides and directly behind the trailer", "Only on the driver's side", "Trucks have no blind spots due to mirrors"], a: 1, exp: "Trucks have large blind spots (\"No-Zones\") on both sides and directly behind — avoid lingering there." },
  { id: "sr05", category: "sharing", q: "When you see a pedestrian who is blind (using a white cane or guide dog), you must:", choices: ["Honk to alert them of your presence", "Always yield the right-of-way", "Only slow down, no need to fully stop", "Ignore normal crosswalk rules since they can't see you"], a: 1, exp: "Drivers must always yield the right-of-way to a pedestrian who is blind, identified by a white cane or guide dog." },
  { id: "sr06", category: "sharing", q: "Bicyclists on the road are generally required to follow:", choices: ["No traffic laws, they are exempt", "The same traffic laws as motor vehicle drivers", "Only pedestrian rules", "Different laws only when riding on sidewalks"], a: 1, exp: "Bicyclists must obey the same rules of the road as other vehicle drivers, including signals and right-of-way." },
  { id: "sr07", category: "sharing", q: "Before opening your car door after parking on a street, you should:", choices: ["Open it quickly to avoid holding up traffic", "Check your mirror and look over your shoulder for bicyclists or traffic", "Only check the side mirror", "No precaution is necessary if parked legally"], a: 1, exp: "Dooring is a major hazard to cyclists — always check mirrors and look back before opening a door into traffic." },
  { id: "sr08", category: "sharing", q: "When a large truck is making a right turn, it may need to swing wide to the left first. You should:", choices: ["Try to squeeze between the truck and the curb", "Stay back and give the truck room to complete the turn", "Honk and pass on the right immediately", "Assume it's turning left instead"], a: 1, exp: "Large trucks need extra room to complete turns — never try to pass on the right side during a truck's turn." },
  { id: "sr09", category: "sharing", q: "When approaching a horse being ridden or led on the road, you should:", choices: ["Honk to alert the horse", "Slow down, give as much room as possible, and avoid sudden noise or movement", "Speed past quickly", "Flash your high beams"], a: 1, exp: "Horses can spook easily — slow down, keep distance, and avoid sudden noises or movements." },
  { id: "sr10", category: "sharing", q: "A person using a wheelchair or a slow-moving mobility device on the road should be treated:", choices: ["As a pedestrian, and given the right-of-way accordingly", "As a vehicle with no special right-of-way", "As an obstacle to drive around quickly", "With no specific rule applying"], a: 0, exp: "Wheelchair users are treated as pedestrians and given the right-of-way like any other pedestrian." },
  { id: "sr11", category: "sharing", q: "When you see a slow-moving vehicle sign (an orange or yellow-green reflective triangle) on a vehicle, it means:", choices: ["The vehicle is broken down and will be towed", "The vehicle travels 25 mph or less, like farm equipment", "You should not pass it under any circumstances", "It's a construction zone marker"], a: 1, exp: "The triangular slow-moving vehicle emblem warns that the vehicle typically travels 25 mph or slower." },
  { id: "sr12", category: "sharing", q: "Bicyclists riding at night are required to have:", choices: ["No lighting requirements at all", "A white front light and a red rear reflector (or rear light)", "Only a horn", "Reflective clothing is legally sufficient by itself"], a: 1, exp: "California law requires a front white light visible from a distance and a red rear reflector/light for night riding." },

  // ===================== ADVERSE CONDITIONS =====================
  { id: "ac01", category: "adverse", q: "If your vehicle begins to hydroplane, you should:", choices: ["Brake hard immediately", "Ease off the accelerator and avoid sudden braking or steering", "Turn the wheel sharply to regain grip", "Accelerate to punch through the water"], a: 1, exp: "Ease off the gas and let the vehicle slow down naturally; sudden inputs can cause loss of control when tires regain traction." },
  { id: "ac02", category: "adverse", q: "If your rear wheels start to skid on a slippery surface, you should:", choices: ["Brake hard immediately", "Take your foot off the gas and steer gently in the direction of the skid", "Steer opposite the direction of the skid", "Accelerate to straighten out"], a: 1, exp: "Ease off the accelerator and steer in the direction the rear of the car is sliding to help regain control." },
  { id: "ac03", category: "adverse", q: "Your blind spots are best checked by:", choices: ["Looking only at your side mirrors", "Turning your head and looking over your shoulder", "Trusting your rearview mirror alone", "Using cruise control's automatic sensors only"], a: 1, exp: "Mirrors cannot fully cover blind spots — always glance over your shoulder before changing lanes or merging." },
  { id: "ac04", category: "adverse", q: "In heavy fog, you should use:", choices: ["High beam headlights for maximum visibility", "Low beam headlights, since high beams reflect off fog and reduce visibility", "No headlights at all", "Only your hazard lights while driving"], a: 1, exp: "High beams reflect off fog and worsen glare — low beams (or fog lights) improve visibility in fog." },
  { id: "ac05", category: "adverse", q: "Driving while drowsy is dangerous mainly because:", choices: ["It only affects your comfort, not your driving", "It slows reaction time and can cause you to fall asleep at the wheel", "It only matters on long road trips", "Coffee completely eliminates the risk"], a: 1, exp: "Fatigue impairs reaction time and judgment similarly to alcohol, and can lead to falling asleep while driving." },
  { id: "ac06", category: "adverse", q: "Texting or using a smartphone while driving is dangerous chiefly because it causes:", choices: ["Manual, visual, and cognitive distraction all at once", "Only a minor visual distraction", "No real danger if done at red lights only", "Distraction only for new drivers"], a: 0, exp: "Texting combines taking your hands off the wheel, eyes off the road, and mind off driving — the most dangerous distraction type." },
  { id: "ac07", category: "adverse", q: "When driving down a long, steep grade, you should:", choices: ["Shift to a lower gear and ride the brakes lightly, rather than riding them continuously", "Keep your foot on the brake continuously the entire way down", "Shift to neutral to save fuel", "Turn off the engine to coast"], a: 0, exp: "Use a lower gear for engine braking on steep downgrades; continuous heavy braking can overheat brakes and cause failure." },
  { id: "ac08", category: "adverse", q: "If your brakes fail while driving, you should:", choices: ["Pump the brake pedal and shift to a lower gear to slow down", "Turn off the engine immediately at full speed", "Jump out of the vehicle", "Pull the hand brake as hard as possible with no pumping"], a: 0, exp: "Pump the brakes (they may regain some pressure), downshift, and carefully use the parking brake to slow down." },
  { id: "ac09", category: "adverse", q: "During strong winds, especially in an SUV, truck, or when towing, you should:", choices: ["Speed up to punch through gusts", "Slow down and keep a firm, steady grip on the wheel", "Drive with one hand for better feel", "Ignore wind, it doesn't affect vehicles"], a: 1, exp: "Reduce speed and maintain a firm grip, especially on high-profile vehicles or when passing large trucks in wind." },
  { id: "ac10", category: "adverse", q: "The three-second rule is used to:", choices: ["Judge how long a yellow light will last", "Determine a safe following distance behind the vehicle ahead", "Time how long to signal before turning", "Estimate speed limits on unmarked roads"], a: 1, exp: "Pick a fixed point the vehicle ahead passes, then count — you should reach it no sooner than 3 seconds later (more in poor conditions)." },
  { id: "ac11", category: "adverse", q: "In poor weather or when following a motorcycle, a large truck, or at night, you should:", choices: ["Keep the same 3-second gap as normal", "Increase your following distance beyond the standard 3-second rule", "Follow closer so you can see around them", "Turn on your high beams to compensate"], a: 1, exp: "Add extra following distance in poor conditions or behind vehicles that are harder to see around or that stop unpredictably." },
  { id: "ac12", category: "adverse", q: "If you see brake lights suddenly come on far ahead of you in a line of traffic, you should:", choices: ["Ignore it since it's far away", "Ease off the gas and cover the brake, anticipating a slowdown", "Speed up to get around before it reaches you", "Change lanes immediately without checking mirrors"], a: 1, exp: "Anticipating trouble ahead (searching well down the road) is a key defensive-driving habit that gives you time to react smoothly." },

  // ===================== PROVISIONAL LICENSE RULES =====================
  { id: "pl01", category: "provisional", q: "During the first 12 months after getting a provisional license, a driver under 18 may not drive between:", choices: ["10 p.m. and 6 a.m.", "11 p.m. and 5 a.m., unless with a licensed driver 25 or older (or for approved reasons)", "Midnight and 4 a.m. only on weekends", "There is no nighttime restriction"], a: 1, exp: "Provisional license holders can't drive from 11 p.m. to 5 a.m. during the first year unless accompanied by a licensed driver 25+, or for school/work/medical necessity with documentation." },
  { id: "pl02", category: "provisional", q: "For the first 12 months, a provisional license holder generally may not transport passengers under age 20 unless:", choices: ["A licensed driver 25 years or older is also in the vehicle", "The passenger is a sibling", "It's during daylight hours", "They have a note from a parent"], a: 0, exp: "During the first year, provisional drivers can't carry passengers under 20 without a 25+ licensed driver present, with some exceptions (school, medical, work related and documented)." },
  { id: "pl03", category: "provisional", q: "A provisional license holder under 18 may use a cell phone while driving:", choices: ["Anytime, hands-free", "Only to contact law enforcement, a medical provider, or emergency services", "Only while parked at a red light", "For music or GPS navigation only"], a: 1, exp: "Drivers under 18 cannot use a wireless device at all while driving, even hands-free, except in a genuine emergency." },
  { id: "pl04", category: "provisional", q: "How long must you typically hold your instruction permit before you're eligible to take the driving test (if under 18)?", choices: ["30 days", "6 months", "1 year", "There is no minimum holding period"], a: 1, exp: "Applicants under 18 must generally hold their permit at least 6 months before taking the behind-the-wheel drive test (this can differ for those 17½ or older who complete driver ed/training, or who wait until 18)." },
  { id: "pl05", category: "provisional", q: "How many total hours of supervised practice driving are required before the drive test for a minor?", choices: ["20 hours", "50 hours, including 10 hours at night", "100 hours", "There is no specific requirement"], a: 1, exp: "California requires 50 hours of supervised practice, including at least 10 hours of night driving, certified by a parent/guardian." },
  { id: "pl06", category: "provisional", q: "A person supervising a permit holder while they drive must be a licensed driver who is:", choices: ["At least 18 years old", "At least 21 years old", "At least 25 years old, seated in the front passenger seat", "Any age as long as they have a license"], a: 2, exp: "The supervising licensed driver must be at least 25 years old and sit in the front passenger seat at all times." },
  { id: "pl07", category: "provisional", q: "If you are at least 17½ years old, you may obtain an instruction permit:", choices: ["Only if you complete driver education and driver training first", "Without completing driver education or driver training", "Only with a court order", "Never — you must wait until 18"], a: 1, exp: "The DMV allows applicants 17½ or older to get an instruction permit without driver education/training certificates, though a driver's license still requires either those certificates or waiting until age 18." },
  { id: "pl08", category: "provisional", q: "A 17½-year-old who skips driver education/training to get their permit sooner will need to, before getting an actual driver's license:", choices: ["Complete driver education and driver training anyway, or simply wait until they turn 18", "Pay an extra fee instead of completing the courses", "Take an additional written test", "Nothing extra is required"], a: 0, exp: "To get the actual driver's license before 18, proof of completed driver education and training is still required; otherwise the applicant must simply wait until their 18th birthday, when those requirements no longer apply." },
  { id: "pl09", category: "provisional", q: "Once a driver turns 18, which of the following permit/license rules generally no longer applies?", choices: ["The requirement for a parent/guardian signature and driver education/training certificates", "Basic traffic laws like stop signs", "The Basic Speed Law", "Seat belt requirements"], a: 0, exp: "Turning 18 removes the driver education/training prerequisite and parental signature requirement for licensing, since the applicant is now an adult." },
  { id: "pl10", category: "provisional", q: "An instruction permit in California is generally valid for how long from the date of issuance?", choices: ["90 days", "6 months", "12 months", "2 years"], a: 2, exp: "The instruction permit / application is valid for 12 months from issuance; the knowledge test must be passed within that window." },
  { id: "pl11", category: "provisional", q: "While driving on a permit, at all times you must be accompanied by:", choices: ["Any adult over 18", "A licensed driver 25 or older, seated beside you", "A parent only, no other adult qualifies", "No supervision is required after the first week"], a: 1, exp: "Permit holders must always have a licensed driver 25+ in the front passenger seat while driving, no exceptions." },
  { id: "pl12", category: "provisional", q: "Exceptions to the nighttime driving restriction for provisional license holders can include documented needs such as:", choices: ["Going to a friend's house for fun", "Employment necessity, medical necessity, or school activities", "Wanting to avoid daytime traffic", "There are no exceptions ever allowed"], a: 1, exp: "Documented exceptions exist for employment, medical necessity, school/extracurricular activities, and immediate family emergencies." },
  { id: "pl13", category: "provisional", q: "If a provisional driver violates the passenger or curfew restrictions, consequences can include:", choices: ["No consequence since it's a minor rule", "Possible citation and it can affect license status/insurance", "Automatic revocation of the parent's license", "A warning only, with no citation possible"], a: 1, exp: "Violating provisional restrictions can result in a citation, points, and consequences for the young driver's license." },
  { id: "pl14", category: "provisional", q: "The provisional license restrictions (curfew and passenger rules) last for:", choices: ["The first 90 days only", "The first 12 months after getting the license, or until turning 18, whichever comes first", "Until you turn 21", "Forever, even as an adult"], a: 1, exp: "These restrictions apply for the first 12 months of licensure or until the driver turns 18, whichever happens first." },
  { id: "pl15", category: "provisional", q: "Which of these is NOT one of the standard first-year provisional license restrictions?", choices: ["No driving 11 p.m.-5 a.m. without a 25+ licensed driver", "No passengers under 20 without a 25+ licensed driver", "No cell phone use, even hands-free", "A lower freeway speed limit than adult drivers"], a: 3, exp: "There is no separate, lower freeway speed limit specifically for provisional drivers — the curfew, passenger, and phone rules are the defining restrictions." },

  // ===================== PERMIT PROCESS / TESTING =====================
  { id: "pp01", category: "process", q: "The minimum age to apply for a learner's permit (instruction permit) in California is:", choices: ["14 years old", "15½ years old", "16 years old", "17 years old"], a: 1, exp: "Applicants must be at least 15½ years old to apply for an instruction permit." },
  { id: "pp02", category: "process", q: "For an applicant under 18, the DMV knowledge (written) test for a Class C permit typically has how many questions?", choices: ["25 questions", "36 questions", "46 questions", "60 questions"], a: 2, exp: "Minors take a 46-question knowledge test; adult (18+) first-time applicants take a 36-question version." },
  { id: "pp03", category: "process", q: "To pass the knowledge test as a minor, you need to answer at least how many of the 46 questions correctly?", choices: ["30 correct", "33 correct", "38 correct", "42 correct"], a: 2, exp: "A minor must answer at least 38 of 46 questions correctly — about an 83% passing score." },
  { id: "pp04", category: "process", q: "How many total attempts do you get to pass the written knowledge test before you must reapply and pay the fee again?", choices: ["1 attempt", "2 attempts", "3 attempts", "Unlimited attempts"], a: 2, exp: "You get 3 attempts within your 12-month application window before needing to submit a new application." },
  { id: "pp05", category: "process", q: "If a minor fails the written knowledge test, how long must they wait before retaking it?", choices: ["Same day retake allowed", "7 days (not counting the day of the failure)", "30 days", "There is no waiting period"], a: 1, exp: "Minors must wait 7 days, not including the day they failed, before retesting." },
  { id: "pp06", category: "process", q: "During the actual knowledge test, are you allowed to use the California Driver Handbook or your phone for reference?", choices: ["Yes, the handbook is allowed", "No, no reference materials or testing aids are allowed", "Only a phone calculator is allowed", "Only for the sign-recognition portion"], a: 1, exp: "No testing aids — including the handbook or a phone — are allowed during the official knowledge test." },
  { id: "pp07", category: "process", q: "To apply for a permit, a minor applicant generally needs which of the following?", choices: ["A parent/guardian's signature/approval and completed driver education certificate (or be 17½+)", "Only their own signature", "A employer's letter of recommendation", "Nothing beyond a birth certificate"], a: 0, exp: "Minors need parent/guardian approval (through MyDMV) and, unless 17½ or older, a driver education completion certificate." },
  { id: "pp08", category: "process", q: "How many attempts are allowed for the behind-the-wheel driving test before you must reapply?", choices: ["1 attempt", "2 attempts", "3 attempts", "5 attempts"], a: 2, exp: "Like the written test, you get 3 attempts at the drive test before needing to reapply." },
  { id: "pp09", category: "process", q: "If a minor fails the behind-the-wheel drive test, how long must they wait before retaking it?", choices: ["No waiting period", "14 days (not counting the day of the failure)", "60 days", "6 months"], a: 1, exp: "Minors must wait 14 days before a retest, and a retest fee applies." },
  { id: "pp10", category: "process", q: "Which of these vehicle conditions could cause you to fail (or be turned away from) the behind-the-wheel drive test?", choices: ["Tires with less than 1/32-inch of tread depth, or a broken mirror/horn/seatbelt", "A car that is more than 5 years old", "A car that isn't fully washed", "Having less than a full tank of gas"], a: 0, exp: "The test vehicle must be safe to operate: adequate tread depth, working brakes/horn/mirrors/seatbelts/turn signals, and valid registration/insurance." },
  { id: "pp11", category: "process", q: "An instruction permit application and required tests remain valid for how long from the date you apply?", choices: ["6 months", "12 months", "18 months", "24 months"], a: 1, exp: "You must complete the permit/testing process within 12 months of your application, or you'll need to reapply and repay fees." },
  { id: "pp12", category: "process", q: "As part of the in-person DMV appointment for a first permit, you should expect to:", choices: ["Only take a photo, with no other requirements", "Provide ID/residency proof, pass a vision exam, get a photo taken, and take the knowledge test", "Take the behind-the-wheel test the same day", "Only need to bring cash for a fine"], a: 1, exp: "The initial appointment covers identity/residency verification, a vision exam, a photo, and the written knowledge test — the driving test comes later." },
];

